section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "claude-messages-api-output",
  "required": ["stop_reason_centralised", "max_tokens_explicit", "multimodal_image_first", "pdf_preflight_check", "metadata_user_id", "streaming_delta_aware", "forbidden_seen"],
  "properties": {
    "stop_reason_centralised": {"description": "Single helper validates stop_reason."},
    "max_tokens_explicit": {"description": "Every call site passes max_tokens explicitly."},
    "multimodal_image_first": {"description": "Image content precedes text in user array."},
    "pdf_preflight_check": {"description": "PDF page+size validated before encoding."},
    "metadata_user_id": {"description": "metadata.user_id set on every call."},
    "streaming_delta_aware": {"description": "Delta parser routes text vs input_json vs thinking."},
    "model_id": {"description": "Full-date pinned id."},
    "forbidden_seen": {"description": "Forbidden patterns; must be empty."}
  }
}
